INSERT INTO `justifications` (`id`, `programId`, `gaId`, `competencyId`, `textEn`, `textAr`, `createdAt`, `updatedAt`) VALUES
(1, 19, 1, 1, 'This competency is most strongly mapped to PLO1 (0.4) as analyzing accounting issues critically requires a strong foundation in accounting principles, standards, and practices. It also maps moderately to PLO2 (0.3), PLO4 (0.3), and PLO5 (0.3) as understanding sustainability implications, using information technology, and evaluating global issues all require foundational accounting knowledge.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(2, 19, 1, 2, 'This competency is most strongly mapped to PLO1 (1.0) as critical thinking is the core competency in analyzing accounting issues. It also maps substantially to PLO2 (0.5) as analyzing sustainability implications requires critical evaluation of environmental, social, and governance factors, and moderately to PLO5 (0.4) as evaluating global accounting issues requires critical assessment of different regulatory environments.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(3, 19, 1, 3, 'This competency is strongly mapped to PLO1 (0.6) as developing innovative solutions to accounting issues is fundamentally a problem-solving activity. It also maps moderately to PLO2 (0.4) and PLO4 (0.5) as making accounting decisions that consider sustainability and using information technology both involve solving complex problems.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(4, 19, 1, 4, 'This competency maps moderately to PLO1 (0.5) and PLO4 (0.5) as coming up with innovative solutions and formulating decisions using technology both require novel and adaptive thinking approaches.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(5, 19, 2, 5, 'This competency is not explicitly mapped to the Accounting PLOs as they focus on technical and analytical skills rather than self-reflection.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(6, 19, 2, 6, 'This competency maps moderately to PLO4 (0.4) as formulating business decisions using information technology requires adapting to new technological tools and systems.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(7, 19, 2, 7, 'This competency maps moderately to PLO4 (0.4) as using information technology for decision-making requires flexible thinking to apply different technological solutions.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(8, 19, 2, 8, 'This competency is not explicitly mapped as the PLOs focus on specific competencies rather than ongoing learning disposition.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(9, 19, 3, 9, 'This competency maps moderately to PLO5 (0.5) as evaluating accounting issues from a global perspective requires understanding and appreciation of diverse cultural business practices.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(10, 19, 3, 10, 'This competency is not explicitly mapped as the Accounting PLOs focus on analytical and decision-making skills rather than communication mechanics.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(11, 19, 3, 11, 'This competency is most strongly mapped to PLO5 (1.0) as it directly requires understanding global accounting issues. It also maps substantially to PLO2 (0.6) as sustainability issues have both local and international dimensions.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(12, 19, 4, 12, 'This competency is not mapped as the Accounting PLOs are secular in nature and do not explicitly address religious or cultural identity.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(13, 19, 4, 13, 'This competency maps minimally to PLO3 (0.3) as incorporating ethical dimensions requires considering diverse stakeholder perspectives.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(14, 19, 4, 14, 'This competency is most strongly mapped to PLO3 (1.0) as it directly requires incorporating ethical dimensions in business decision-making, which is central to professional accounting practice.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(15, 19, 4, 15, 'This competency maps moderately to PLO2 (0.4) and minimally to PLO3 (0.3) as considering sustainability and ethical dimensions both involve social responsibility and civic awareness.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(16, 19, 4, 16, 'This competency maps moderately to PLO2 (0.5) and PLO5 (0.6) as sustainability issues and global accounting perspectives both require engagement with broader community and international concerns.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(17, 19, 5, 17, 'This competency maps moderately to PLO1 (0.5) as coming up with innovative solutions to accounting issues directly requires creativity.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(18, 19, 5, 18, 'This competency is not explicitly mapped as the Accounting PLOs focus on individual analytical skills rather than teamwork.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(19, 19, 5, 19, 'This competency is not explicitly mapped as the PLOs focus on accounting analysis rather than management functions.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(20, 19, 5, 20, 'This competency is not explicitly mapped as the PLOs focus on technical and analytical skills rather than interpersonal interaction.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(21, 19, 5, 21, 'This competency is not explicitly mapped as the PLOs do not directly address leadership capabilities.', '', '2026-02-20 12:25:54', '2026-02-20 12:25:54'),
(22, 20, 1, 1, 'This competency maps moderately to PLO1 (0.5) as applying quantitative skills requires foundational knowledge in economics and quantitative methods. It maps strongly to PLO2 (0.6) as applying economic concepts and theories requires deep subject-matter understanding. It also maps moderately to PLO4 (0.4) and PLO5 (0.4) as analyzing local/regional and global economic issues requires solid grounding in economic principles.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(23, 20, 1, 2, 'This competency maps moderately to PLO1 (0.5) as developing innovative solutions requires analytical thinking. It maps moderately to PLO2 (0.5) as explaining sustainability implications demands critical evaluation. It maps moderately to PLO3 (0.5) as identifying and analyzing ethical issues is fundamentally a critical-thinking activity. It maps substantially to PLO4 (0.6) and PLO5 (0.6) as analyzing local/regional and global economic issues requires strong critical assessment capabilities.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(24, 20, 1, 3, 'This competency is most strongly mapped to PLO1 (1.0) as developing innovative solutions for economic problems is the core problem-solving activity. It also maps moderately to PLO4 (0.5) as analyzing local and regional economic issues involves problem identification and solution development.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(25, 20, 1, 4, 'This competency maps moderately to PLO1 (0.5) as developing innovative solutions requires novel and adaptive thinking approaches. It also maps moderately to PLO4 (0.4) as using appropriate technologies and tools to analyze economic issues requires adaptive thinking.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(26, 20, 2, 5, 'This competency is not explicitly mapped to the Economics PLOs as they focus on analytical and technical skills rather than self-reflection.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(27, 20, 2, 6, 'This competency is not explicitly mapped as the Economics PLOs emphasize analysis and application rather than personal adaptability.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(28, 20, 2, 7, 'This competency is not explicitly mapped as the PLOs focus on economic analysis rather than adaptive thinking processes.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(29, 20, 2, 8, 'This competency is not explicitly mapped as the PLOs focus on specific competencies rather than ongoing learning disposition.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(30, 20, 3, 9, 'This competency maps moderately to PLO5 (0.5) as explaining and evaluating global economic issues requires understanding and appreciation of diverse cultural and economic systems.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(31, 20, 3, 10, 'This competency is not explicitly mapped as the Economics PLOs focus on analytical and decision-making skills rather than communication mechanics.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(32, 20, 3, 11, 'This competency is most strongly mapped to PLO5 (1.0) as it directly requires understanding and evaluating global economic issues. It maps substantially to PLO4 (0.8) as analyzing local and regional economic issues is a primary focus. It also maps substantially to PLO2 (0.6) as sustainability has both local and international dimensions.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(33, 20, 4, 12, 'This competency is not mapped as the Economics PLOs are secular in nature and do not explicitly address religious or cultural identity.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(34, 20, 4, 13, 'This competency maps minimally to PLO3 (0.3) as identifying and analyzing ethical issues requires considering diverse stakeholder perspectives.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(35, 20, 4, 14, 'This competency is most strongly mapped to PLO3 (1.0) as it directly requires identifying and analyzing ethical issues in economics and decision-making, which is central to professional conduct in economics.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(36, 20, 4, 15, 'This competency maps moderately to PLO2 (0.4) and minimally to PLO3 (0.3) as sustainability implications and ethical issues both involve social responsibility and civic awareness.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(37, 20, 4, 16, 'This competency maps moderately to PLO2 (0.5) as sustainability issues require engagement with broader community concerns. It maps substantially to PLO5 (0.6) as evaluating global economic issues requires engagement with international economic communities.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(38, 20, 5, 17, 'This competency maps moderately to PLO1 (0.5) as developing innovative solutions for economic problems directly requires creativity and innovation.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(39, 20, 5, 18, 'This competency is not explicitly mapped as the Economics PLOs focus on individual analytical skills rather than teamwork.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(40, 20, 5, 19, 'This competency is not explicitly mapped as the PLOs focus on economic analysis rather than management functions.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(41, 20, 5, 20, 'This competency is not explicitly mapped as the PLOs focus on technical and analytical skills rather than interpersonal interaction.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(42, 20, 5, 21, 'This competency is not explicitly mapped as the PLOs do not directly address leadership capabilities.', '', '2026-02-20 12:32:16', '2026-02-20 12:32:16'),
(43, 21, 1, 1, 'This competency is most strongly mapped to PLO1 (1.0) as explaining, analyzing, interpreting, and synthesizing fundamental financial theories requires deep mastery of finance subject matter. It also maps moderately to PLO2 (0.3), PLO4 (0.3), and PLO5 (0.4) as discussing sustainability, using technology tools, and applying global economy knowledge all require foundational finance expertise.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(44, 21, 1, 2, 'This competency is strongly mapped to PLO1 (0.7) as analyzing and interpreting financial theories requires substantial critical thinking. It maps moderately to PLO2 (0.5) as discussing sustainability applications requires critical evaluation, substantially to PLO3 (0.6) as identifying ethical implications and analyzing alternatives is fundamentally critical thinking, and moderately to PLO5 (0.5) as applying global economy knowledge requires critical assessment.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(45, 21, 1, 3, 'This competency maps moderately to PLO1 (0.4) and PLO2 (0.4) as synthesizing theories and discussing sustainability involve problem-solving. It maps moderately to PLO3 (0.5) as analyzing alternatives and recommending actions is problem-solving. It maps strongly to PLO4 (0.7) as providing innovative solutions to financial problems is the core problem-solving activity, and substantially to PLO5 (0.6) as recommending solutions to business problems requires problem-solving skills.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(46, 21, 1, 4, 'This competency maps minimally to PLO1 (0.3) as synthesizing theories requires some novel thinking. It maps substantially to PLO4 (0.6) as identifying appropriate technology tools and providing innovative solutions requires novel and adaptive thinking approaches.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(47, 21, 2, 5, 'This competency is not explicitly mapped to the Finance PLOs as they focus on technical and analytical skills rather than self-reflection.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(48, 21, 2, 6, 'This competency maps moderately to PLO4 (0.4) as identifying and using appropriate technology tools requires adapting to new technological solutions.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(49, 21, 2, 7, 'This competency maps moderately to PLO4 (0.4) as providing innovative solutions using technology requires flexible and adaptive thinking.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(50, 21, 2, 8, 'This competency is not explicitly mapped as the PLOs focus on specific competencies rather than ongoing learning disposition.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(51, 21, 3, 9, 'This competency maps moderately to PLO5 (0.5) as applying knowledge of the global economy and international business requires understanding and appreciation of diverse cultural and business practices.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(52, 21, 3, 10, 'This competency is not explicitly mapped as the Finance PLOs focus on analytical and decision-making skills rather than communication mechanics.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(53, 21, 3, 11, 'This competency is most strongly mapped to PLO5 (1.0) as it directly requires applying knowledge of the global economy and international business. It also maps substantially to PLO2 (0.6) as sustainability issues have both local and international dimensions.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(54, 21, 4, 12, 'This competency is not mapped as the Finance PLOs are secular in nature and do not explicitly address religious or cultural identity.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(55, 21, 4, 13, 'This competency maps minimally to PLO3 (0.3) as identifying ethical implications and analyzing alternatives requires considering diverse stakeholder perspectives.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(56, 21, 4, 14, 'This competency is most strongly mapped to PLO3 (1.0) as it directly requires identifying ethical implications, analyzing alternatives, and recommending appropriate actions, which is central to professional conduct in finance.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(57, 21, 4, 15, 'This competency maps moderately to PLO2 (0.4) and minimally to PLO3 (0.3) as sustainability applications and ethical implications both involve social responsibility and civic awareness.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(58, 21, 4, 16, 'This competency maps moderately to PLO2 (0.5) as sustainability issues require engagement with broader community concerns. It maps substantially to PLO5 (0.6) as applying global economy knowledge requires engagement with international business communities.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(59, 21, 5, 17, 'This competency maps moderately to PLO4 (0.5) as providing innovative solutions to real-life financial problems directly requires creativity and innovation.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(60, 21, 5, 18, 'This competency is not explicitly mapped as the Finance PLOs focus on individual analytical skills rather than teamwork.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(61, 21, 5, 19, 'This competency is not explicitly mapped as the PLOs focus on finance analysis and decision-making rather than management functions.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(62, 21, 5, 20, 'This competency is not explicitly mapped as the PLOs focus on technical and analytical skills rather than interpersonal interaction.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(63, 21, 5, 21, 'This competency is not explicitly mapped as the PLOs do not directly address leadership capabilities.', '', '2026-02-20 12:32:39', '2026-02-20 12:32:39'),
(64, 22, 1, 1, 'This competency is strongly mapped to PLO1 (0.7) as assessing and applying management theories and best practices requires deep subject-matter knowledge in management. It maps moderately to PLO2 (0.4) and PLO5 (0.4) as formulating strategic and international business decisions requires foundational management expertise.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(65, 22, 1, 2, 'This competency maps substantially to PLO1 (0.6) as assessing management theories and solving business problems requires critical evaluation. It maps moderately to PLO3 (0.5) and PLO5 (0.5) as developing ethical decisions and formulating international business decisions both require critical thinking.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(66, 22, 1, 3, 'This competency is most strongly mapped to PLO1 (1.0) as solving business problems is the core focus. It maps substantially to PLO2 (0.6), PLO4 (0.6), and PLO5 (0.6) as formulating strategic decisions, determining sustainable decisions, and formulating international decisions are all problem-solving activities.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(67, 22, 1, 4, 'This competency maps moderately to PLO2 (0.5) and PLO4 (0.5) as responding to environmental changes and determining creative sustainable solutions both require novel and adaptive thinking.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(68, 22, 2, 5, 'This competency is not explicitly mapped to the Management PLOs as they focus on decision-making and problem-solving rather than self-reflection.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(69, 22, 2, 6, 'This competency maps substantially to PLO2 (0.6) as formulating strategic business decisions in response to environmental changes directly requires adaptability.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(70, 22, 2, 7, 'This competency maps substantially to PLO2 (0.6) as responding to environmental changes using appropriate technology requires adaptive thinking.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(71, 22, 2, 8, 'This competency is not explicitly mapped as the PLOs focus on specific competencies rather than ongoing learning disposition.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(72, 22, 3, 9, 'This competency maps substantially to PLO5 (0.6) as formulating effective international business decisions requires understanding and appreciation of diverse cultural business practices.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(73, 22, 3, 10, 'This competency is not explicitly mapped as the Management PLOs focus on decision-making and problem-solving rather than communication mechanics.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(74, 22, 3, 11, 'This competency is most strongly mapped to PLO5 (1.0) as it directly requires formulating international business decisions in response to global challenges. It also maps strongly to PLO4 (0.7) as sustainable business decisions address environmental, social, and economic challenges with both local and global dimensions.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(75, 22, 4, 12, 'This competency is not mapped as the Management PLOs are secular in nature and do not explicitly address religious or cultural identity.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(76, 22, 4, 13, 'This competency maps minimally to PLO3 (0.3) as developing ethical decisions requires considering diverse stakeholder perspectives.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(77, 22, 4, 14, 'This competency is most strongly mapped to PLO3 (1.0) as it directly requires developing ethical decisions in response to business ethical dilemmas.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(78, 22, 4, 15, 'This competency maps minimally to PLO3 (0.3) and substantially to PLO4 (0.6) as ethical decisions and sustainable business decisions both involve social responsibility and civic engagement.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(79, 22, 4, 16, 'This competency maps strongly to PLO4 (0.7) and PLO5 (0.7) as sustainable business decisions and international business decisions both require engagement with community and global stakeholders.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(80, 22, 5, 17, 'This competency maps substantially to PLO4 (0.6) as determining creative sustainable business decisions directly requires creativity and innovation.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(81, 22, 5, 18, 'This competency is not explicitly mapped as the Management PLOs focus on decision-making skills rather than teamwork.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(82, 22, 5, 19, 'This competency is strongly mapped to PLO1 (0.8) as assessing and applying management theories is the core management activity. It maps strongly to PLO2 (0.7) as formulating strategic business decisions is a key management function. It maps moderately to PLO4 (0.5) and substantially to PLO5 (0.6) as determining sustainable decisions and formulating international decisions both require management capabilities.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(83, 22, 5, 20, 'This competency is not explicitly mapped as the PLOs focus on decision-making skills rather than interpersonal interaction.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(84, 22, 5, 21, 'This competency maps moderately to PLO3 (0.4) as developing ethical decisions in response to dilemmas requires leadership in ethical conduct.', '', '2026-02-20 12:33:18', '2026-02-20 12:33:18'),
(85, 23, 1, 1, 'This competency is strongly mapped to PLO1 (0.8) as planning, analyzing, and designing information systems requires deep subject-matter expertise in information systems. It maps moderately to PLO2 (0.5), PLO4 (0.5), and PLO5 (0.4) as managing data, evaluating technologies, and analyzing global perspectives all require foundational IS knowledge.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(86, 23, 1, 2, 'This competency maps substantially to PLO1 (0.6) as analyzing and designing information systems requires critical thinking. It maps strongly to PLO2 (0.7) as making innovative business decisions from data requires critical analysis. It maps substantially to PLO3 (0.6), PLO4 (0.6), and PLO6 (0.6) as analyzing ethical dimensions, evaluating technologies, and analyzing sustainability impacts all require critical thinking.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(87, 23, 1, 3, 'This competency is strongly mapped to PLO1 (0.7) as designing information systems is a problem-solving activity. It maps substantially to PLO2 (0.6) as utilizing data to make decisions involves problem-solving, and moderately to PLO6 (0.4) as analyzing sustainability impacts requires problem identification.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(88, 23, 1, 4, 'This competency maps moderately to PLO1 (0.5) and substantially to PLO2 (0.6) as designing systems and making innovative decisions require novel thinking. It maps strongly to PLO4 (0.7) as evaluating emerging technologies and managing their alignment requires adaptive thinking.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(89, 23, 2, 5, 'This competency is not explicitly mapped to the MIS PLOs as they focus on technical and analytical skills rather than self-reflection.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(90, 23, 2, 6, 'This competency maps substantially to PLO4 (0.6) as evaluating relevant emerging technologies and managing their alignment requires adaptability to technological change.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(91, 23, 2, 7, 'This competency maps substantially to PLO4 (0.6) as managing alignment of emerging technologies with business strategies requires adaptive thinking.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(92, 23, 2, 8, 'This competency maps moderately to PLO4 (0.5) as staying current with emerging technologies requires ongoing learning.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(93, 23, 3, 9, 'This competency maps moderately to PLO5 (0.5) as analyzing global perspectives in information systems decisions requires understanding diverse cultural contexts.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(94, 23, 3, 10, 'This competency is not explicitly mapped as the MIS PLOs focus on analytical and technical skills rather than communication mechanics.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(95, 23, 3, 11, 'This competency is most strongly mapped to PLO5 (1.0) as it directly requires analyzing global perspectives in IS decisions. It also maps strongly to PLO6 (0.7) as environmental sustainability has both local and international dimensions.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(96, 23, 4, 12, 'This competency is not mapped as the MIS PLOs are secular in nature and do not explicitly address religious or cultural identity.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(97, 23, 4, 13, 'This competency maps minimally to PLO3 (0.3) as identifying and analyzing ethical dimensions requires considering diverse stakeholder perspectives.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(98, 23, 4, 14, 'This competency is most strongly mapped to PLO3 (1.0) as it directly requires identifying and analyzing ethical dimensions in business decision-making.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(99, 23, 4, 15, 'This competency maps minimally to PLO3 (0.3) and moderately to PLO6 (0.5) as ethical dimensions and sustainability impacts both involve civic responsibility.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(100, 23, 4, 16, 'This competency maps moderately to PLO5 (0.5) and substantially to PLO6 (0.6) as global IS perspectives and sustainability impacts both require engagement with community and global concerns.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(101, 23, 5, 17, 'This competency maps moderately to PLO1 (0.5) as designing information systems requires creativity. It maps substantially to PLO2 (0.6) as making innovative business decisions directly requires creativity and innovation.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(102, 23, 5, 18, 'This competency is not explicitly mapped as the MIS PLOs focus on individual analytical and technical skills rather than teamwork.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(103, 23, 5, 19, 'This competency maps moderately to PLO1 (0.5) and PLO2 (0.5) as planning and managing data are management functions. It maps substantially to PLO4 (0.6) as managing alignment of technologies with business strategies is a key management activity.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(104, 23, 5, 20, 'This competency is not explicitly mapped as the PLOs focus on technical and analytical skills rather than interpersonal interaction.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(105, 23, 5, 21, 'This competency is not explicitly mapped as the PLOs do not directly address leadership capabilities.', '', '2026-02-20 12:33:40', '2026-02-20 12:33:40'),
(106, 24, 1, 1, 'This competency is strongly mapped to PLO1 (0.7) as explaining marketing concepts and theories requires deep subject-matter knowledge in marketing. It maps moderately to PLO2 (0.4) and PLO5 (0.4) as analyzing technology impacts and evaluating global marketing challenges both require foundational marketing expertise.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(107, 24, 1, 2, 'This competency maps moderately to PLO1 (0.5) as applying marketing theories to develop innovative actions requires critical thinking. It maps strongly to PLO2 (0.7) as analyzing and evaluating technology impacts requires substantial critical evaluation. It maps substantially to PLO3 (0.6) and PLO5 (0.6) as evaluating ethical ramifications and marketing challenges both require critical assessment.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(108, 24, 1, 3, 'This competency maps substantially to PLO1 (0.6) as developing innovative marketing actions is problem-solving. It also maps moderately to PLO4 (0.5) as developing marketing strategies to address sustainability is a problem-solving activity.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(109, 24, 1, 4, 'This competency maps moderately to PLO1 (0.5) as developing innovative marketing actions requires novel thinking. It maps substantially to PLO2 (0.6) as analyzing emerging technologies requires adaptive thinking, and moderately to PLO4 (0.4) as addressing sustainability issues requires adaptive approaches.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(110, 24, 2, 5, 'This competency is not explicitly mapped to the Marketing PLOs as they focus on analytical and strategic skills rather than self-reflection.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(111, 24, 2, 6, 'This competency maps moderately to PLO2 (0.5) as analyzing and evaluating the impact of emerging technologies requires adaptability to technological changes.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(112, 24, 2, 7, 'This competency maps moderately to PLO2 (0.5) as evaluating technology impacts on marketing practices requires adaptive thinking.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(113, 24, 2, 8, 'This competency maps moderately to PLO2 (0.4) as staying current with emerging technologies requires ongoing learning.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(114, 24, 3, 9, 'This competency maps substantially to PLO5 (0.6) as identifying and evaluating marketing challenges in a global context requires understanding and appreciation of diverse cultural practices.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(115, 24, 3, 10, 'This competency is not explicitly mapped as the Marketing PLOs focus on analytical and strategic skills rather than communication mechanics.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(116, 24, 3, 11, 'This competency is most strongly mapped to PLO5 (1.0) as it directly requires evaluating marketing challenges specific to global organizations. It also maps strongly to PLO4 (0.7) as environmental sustainability issues have both local and international dimensions.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(117, 24, 4, 12, 'This competency is not mapped as the Marketing PLOs are secular in nature and do not explicitly address religious or cultural identity.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(118, 24, 4, 13, 'This competency maps minimally to PLO3 (0.3) as recognizing and evaluating ethical ramifications requires considering diverse stakeholder perspectives.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(119, 24, 4, 14, 'This competency is most strongly mapped to PLO3 (1.0) as it directly requires recognizing and evaluating potential ethical ramifications of marketing decisions and actions.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(120, 24, 4, 15, 'This competency maps moderately to PLO3 (0.4) and substantially to PLO4 (0.6) as ethical ramifications and sustainability strategies both involve civic responsibility and social awareness.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(121, 24, 4, 16, 'This competency maps substantially to PLO4 (0.6) and PLO5 (0.6) as sustainability strategies and global marketing challenges both require engagement with community and international stakeholders.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(122, 24, 5, 17, 'This competency is strongly mapped to PLO1 (0.7) as developing innovative marketing actions directly requires creativity and innovation. It also maps moderately to PLO4 (0.5) as developing marketing strategies for sustainability requires creative thinking.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(123, 24, 5, 18, 'This competency is not explicitly mapped as the Marketing PLOs focus on individual analytical and strategic skills rather than teamwork.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(124, 24, 5, 19, 'This competency maps moderately to PLO4 (0.4) as developing marketing strategies and plans is a management function.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(125, 24, 5, 20, 'This competency is not explicitly mapped as the PLOs focus on analytical and strategic skills rather than interpersonal interaction.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(126, 24, 5, 21, 'This competency is not explicitly mapped as the PLOs do not directly address leadership capabilities.', '', '2026-02-20 12:34:01', '2026-02-20 12:34:01'),
(127, 32, 1, 1, 'This competency is most strongly mapped to PLO1 (1.0) as it directly requires applying principles of engineering, science, and mathematics to solve complex problems. It also maps strongly to PLO2 (0.8) and PLO6 (0.8) as design and experimentation both require deep subject matter knowledge.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(128, 32, 1, 2, 'This competency is most strongly mapped to PLO1 (1.0) as formulating and solving complex engineering problems is the essence of critical thinking in this field. It also maps strongly to PLO2 (0.8) and PLO6 (0.8) as design and experimentation require critical evaluation and analysis.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(129, 32, 1, 3, 'This competency is most strongly mapped to PLO1 (1.0) as it is explicitly about solving complex engineering problems. It also maps strongly to PLO2 (0.8) and PLO6 (0.8) as design and experimentation are core problem-solving activities.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(130, 32, 1, 4, 'This competency is most strongly mapped to PLO6 (1.0) as it involves developing and conducting appropriate experimentation. It also maps strongly to PLO1 (0.8), PLO2 (0.8), and PLO7 (0.8) as solving complex problems, designing solutions, and acquiring new knowledge all require novel and adaptive thinking.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(131, 32, 2, 5, 'This competency maps most strongly to PLO7 (0.8) as acquiring new knowledge requires an awareness of one\'s own knowledge gaps. It also maps moderately across PLO3, PLO4, PLO5, and PLO6 (0.5) as communication, ethical responsibility, teamwork, and experimentation all benefit from self-awareness.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(132, 32, 2, 6, 'This competency is most strongly mapped to PLO7 (1.0) as the ability to acquire and apply new knowledge is the definition of adaptability in a professional context. It also maps moderately across PLO1, PLO2, PLO4, PLO5, and PLO6 (0.5) as all these activities require adapting to new information and contexts.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(133, 32, 2, 7, 'This competency is most strongly mapped to PLO7 (1.0) as acquiring and applying new knowledge requires adaptive thinking. It also maps strongly to PLO1 (0.8), PLO2 (0.8), and PLO6 (0.8) as problem-solving, design, and experimentation are all non-linear processes requiring adaptive thinking.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(134, 32, 2, 8, 'This competency is most strongly mapped to PLO7 (1.0) as it directly addresses the ability to acquire and apply new knowledge as needed. It also maps strongly to PLO6 (0.8) as experimentation and data analysis foster a desire for continuous learning.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(135, 32, 3, 9, 'This competency is most strongly mapped to PLO4 (0.8) as it requires considering the impact of engineering solutions in a cultural context. It also maps moderately to PLO2 (0.5) which includes consideration of cultural factors in design.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(136, 32, 3, 10, 'This competency is most strongly mapped to PLO3 (1.0) which is explicitly about communicating effectively with a range of audiences. It also maps strongly to PLO5 (0.8) as teamwork is impossible without effective communication.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(137, 32, 3, 11, 'This competency is most strongly mapped to PLO4 (1.0) as it requires considering the impact of engineering solutions in global, economic, environmental, and societal contexts. It also maps strongly to PLO2 (0.8) which requires consideration of these factors in the design process.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(138, 32, 4, 12, 'This competency has a moderate mapping to PLO4 (0.8) as ethical considerations in a local context will involve an understanding of Arabic-Islamic identity and values. Other PLOs have minimal or no mapping as they are culturally neutral.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(139, 32, 4, 13, 'This competency is most strongly mapped to PLO2 (0.8) and PLO4 (0.8) as both require consideration of cultural and social factors. It also maps moderately to PLO5 (0.5) as teamwork in a diverse environment requires embracing diversity.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(140, 32, 4, 14, 'This competency is most strongly mapped to PLO4 (1.0) as it is explicitly about recognizing ethical and professional responsibilities. It also maps strongly to PLO2 (0.8) as design must consider public health, safety, and welfare.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(141, 32, 4, 15, 'This competency is most strongly mapped to PLO4 (1.0) as it requires considering the impact of engineering solutions in a societal context. It also maps strongly to PLO2 (0.8) which requires consideration of public health, safety, and welfare.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(142, 32, 5, 17, 'This competency is most strongly mapped to PLO2 (1.0) as engineering design is an inherently creative and innovative process. It also maps moderately to PLO1 (0.5), PLO6 (0.5), and PLO7 (0.5) as problem-solving, experimentation, and acquiring new knowledge all involve creativity.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(143, 32, 5, 18, 'This competency is most strongly mapped to PLO5 (1.0) as it is explicitly about functioning effectively on a team. It also maps strongly to PLO3 (0.8) as collaboration requires effective communication.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(144, 32, 5, 19, 'This competency is most strongly mapped to PLO5 (1.0) as teamwork involves planning tasks and meeting objectives, which are management functions. It also maps moderately to PLO2 (0.5) as the design process requires management.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(145, 32, 5, 20, 'This competency is most strongly mapped to PLO5 (1.0) as teamwork requires strong interpersonal skills. It also maps strongly to PLO3 (0.8) as effective communication is a key interpersonal skill.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(146, 32, 5, 21, 'This competency is most strongly mapped to PLO5 (1.0) as it explicitly includes providing leadership within a team. It also maps moderately to PLO2 (0.5), PLO4 (0.5), and PLO7 (0.5) as design, ethical responsibility, and lifelong learning all provide opportunities for leadership.', '', '2026-02-20 13:04:54', '2026-02-20 10:08:30'),
(147, 37, 1, 1, 'This competency is most strongly mapped to PLO1 (1.0) as it directly requires conceptualizing and coordinating designs, which is the core of architectural subject matter. It also maps strongly to PLO3 (0.8) as utilizing cutting-edge technology requires deep subject knowledge.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(148, 37, 1, 2, 'This competency is most strongly mapped to PLO5 (1.0) as it is explicitly about critically analyzing building designs. It also maps strongly to PLO1 (0.8) and PLO6 (0.8) as design and research both require significant critical thinking.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(149, 37, 1, 3, 'This competency is most strongly mapped to PLO5 (1.0) as critically analyzing designs and conducting post-occupancy evaluations are problem-solving activities. It also maps strongly to PLO1 (0.8) and PLO6 (0.8) as design and research are fundamentally about solving problems.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(150, 37, 1, 4, 'This competency is most strongly mapped to PLO6 (1.0) as it is explicitly about employing architectural research methods. It also maps strongly to PLO1 (0.8) and PLO5 (0.8) as design and critical analysis both require novel and adaptive thinking.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(151, 37, 2, 5, 'This competency maps moderately across PLO1, PLO2, PLO4, PLO5, PLO6, and PLO7 (0.5) as all these activities benefit from self-awareness, but it is not the primary focus of any single PLO.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(152, 37, 2, 6, 'This competency is most strongly mapped to PLO1 (0.8) and PLO3 (0.8) as design and technology are constantly evolving, requiring adaptability. It also maps moderately across PLO2, PLO5, PLO6, and PLO7 (0.5).', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(153, 37, 2, 7, 'This competency is most strongly mapped to PLO1 (0.8), PLO3 (0.8), PLO5 (0.8), and PLO6 (0.8) as design, technology, critical thinking, and research all require adaptive thinking to respond to new information and challenges.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(154, 37, 2, 8, 'This competency is most strongly mapped to PLO6 (1.0) as employing research methods fosters a desire for continuous learning. It also maps moderately to PLO5 (0.5) and PLO7 (0.5).', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(155, 37, 3, 9, 'This competency is most strongly mapped to PLO2 (1.0) as it explicitly requires recognizing the dialectic relationship between people and the built environment in the GCC/Arab region. It also maps moderately to PLO1 (0.5) as design must address cultural aspects.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(156, 37, 3, 10, 'This competency is most strongly mapped to PLO4 (1.0) as it is explicitly about applying visual and verbal communication skills. It also maps strongly to PLO7 (0.8) as collaboration requires effective communication.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(157, 37, 3, 11, 'This competency is most strongly mapped to PLO2 (0.8) as it requires recognizing the relationship between people and the built environment in the GCC/Arab region. It also maps moderately to PLO1 (0.5), PLO5 (0.5), and PLO6 (0.5).', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(158, 37, 4, 12, 'This competency is most strongly mapped to PLO2 (0.8) as it requires understanding the cultural context of the GCC/Arab region. It also maps moderately to PLO1 (0.2) and other PLOs as ethical considerations in a local context will involve an understanding of Arabic-Islamic identity and values.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(159, 37, 4, 13, 'This competency is most strongly mapped to PLO2 (1.0) as it is explicitly about recognizing diversity of needs, values, behavioral norms, and social patterns. It also maps moderately to PLO1 (0.5), PLO5 (0.5), and PLO7 (0.5).', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(160, 37, 4, 14, 'This competency maps moderately across PLO1, PLO2, PLO4, PLO5, and PLO7 (0.5) as all these activities require professional and ethical conduct, but it is not the primary focus of any single PLO.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(161, 37, 4, 15, 'This competency is most strongly mapped to PLO2 (0.8) as it requires recognizing the relationship between people and the built environment, which is a core aspect of civic engagement in architecture. It also maps moderately to PLO1 (0.5), PLO5 (0.5), and PLO7 (0.5).', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(162, 37, 5, 17, 'This competency is most strongly mapped to PLO1 (1.0) as design is an inherently creative and innovative process. It also maps strongly to PLO3 (0.8) as utilizing cutting-edge technology requires innovation.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(163, 37, 5, 18, 'This competency is most strongly mapped to PLO7 (1.0) as it is explicitly about working collaboratively with teams. It also maps strongly to PLO4 (0.8) as collaboration requires effective communication.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(164, 37, 5, 19, 'This competency is most strongly mapped to PLO7 (1.0) as working collaboratively in teams involves management functions. It also maps moderately to PLO1 (0.5) and PLO4 (0.5) as design and communication processes require management.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(165, 37, 5, 20, 'This competency is most strongly mapped to PLO7 (1.0) as teamwork requires strong interpersonal skills. It also maps strongly to PLO2 (0.8) and PLO4 (0.8) as understanding people and communicating effectively are key interpersonal skills.', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(166, 37, 5, 21, 'This competency is most strongly mapped to PLO7 (1.0) as working collaboratively provides opportunities for leadership. It also maps moderately to PLO1 (0.5), PLO2 (0.5), and PLO4 (0.5).', '', '2026-02-20 13:27:24', '2026-02-20 13:27:24'),
(167, 29, 1, 1, 'This competency is most strongly mapped to PLO1 (1.0) as it directly requires applying principles of engineering, science, and mathematics to solve complex problems. It also maps strongly to PLO2 (0.8) and PLO6 (0.8) as design and experimentation both require deep subject matter knowledge.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48'),
(168, 29, 1, 2, 'This competency is most strongly mapped to PLO1 (1.0) as formulating and solving complex engineering problems is the essence of critical thinking in this field. It also maps strongly to PLO2 (0.8) and PLO6 (0.8) as design and experimentation require critical evaluation and analysis.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48'),
(169, 29, 1, 3, 'This competency is most strongly mapped to PLO1 (1.0) as it is explicitly about solving complex engineering problems. It also maps strongly to PLO2 (0.8) and PLO6 (0.8) as design and experimentation are core problem-solving activities.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48'),
(170, 29, 1, 4, 'This competency is most strongly mapped to PLO6 (1.0) as it involves developing and conducting appropriate experimentation. It also maps strongly to PLO1 (0.8), PLO2 (0.8), and PLO7 (0.8) as solving complex problems, designing solutions, and acquiring new knowledge all require novel and adaptive thinking.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48'),
(171, 29, 2, 5, 'This competency maps most strongly to PLO7 (0.8) as acquiring new knowledge requires an awareness of one\'s own knowledge gaps. It also maps moderately across PLO3, PLO4, PLO5, and PLO6 (0.5) as communication, ethical responsibility, teamwork, and experimentation all benefit from self-awareness.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48'),
(172, 29, 2, 6, 'This competency is most strongly mapped to PLO7 (1.0) as the ability to acquire and apply new knowledge is the definition of adaptability in a professional context. It also maps moderately across PLO1, PLO2, PLO4, PLO5, and PLO6 (0.5) as all these activities require adapting to new information and contexts.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48'),
(173, 29, 2, 7, 'This competency is most strongly mapped to PLO7 (1.0) as acquiring and applying new knowledge requires adaptive thinking. It also maps strongly to PLO1 (0.8), PLO2 (0.8), and PLO6 (0.8) as problem-solving, design, and experimentation are all non-linear processes requiring adaptive thinking.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48'),
(174, 29, 2, 8, 'This competency is most strongly mapped to PLO7 (1.0) as it directly addresses the ability to acquire and apply new knowledge as needed. It also maps strongly to PLO6 (0.8) as experimentation and data analysis foster a desire for continuous learning.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48'),
(175, 29, 3, 9, 'This competency is most strongly mapped to PLO4 (0.8) as it requires considering the impact of engineering solutions in a cultural context. It also maps moderately to PLO2 (0.5) which includes consideration of cultural factors in design.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48'),
(176, 29, 3, 10, 'This competency is most strongly mapped to PLO3 (1.0) which is explicitly about communicating effectively with a range of audiences. It also maps strongly to PLO5 (0.8) as teamwork is impossible without effective communication.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48'),
(177, 29, 3, 11, 'This competency is most strongly mapped to PLO4 (1.0) as it requires considering the impact of engineering solutions in global, economic, environmental, and societal contexts. It also maps strongly to PLO2 (0.8) which requires consideration of these factors in the design process.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48'),
(178, 29, 4, 12, 'This competency has a moderate mapping to PLO4 (0.8) as ethical considerations in a local context will involve an understanding of Arabic-Islamic identity and values. Other PLOs have minimal or no mapping as they are culturally neutral.', '', '2026-02-20 13:27:48', '2026-02-20 13:27:48');
