(178, 53, 'PLO1', 'Demonstrate knowledge and competencies in sport management needed in various settings and the broader relationship between the industry and society', '', 1, '2026-02-20 13:39:31', '2026-02-20 13:39:31'),
(179, 53, 'PLO2', 'Effectively apply knowledge and skills learned throughout the sport management curriculum in real-world settings, encouraging field experiences and volunteerism', '', 2, '2026-02-20 13:39:31', '2026-02-20 13:39:31'),
(180, 53, 'PLO3', 'Apply critical thinking and reasoning skills in sport management with application into local, regional, and international contexts, as well as awareness of ethical/legal and social responsibility issues', '', 3, '2026-02-20 13:39:31', '2026-02-20 13:39:31'),
(181, 53, 'PLO4', 'Communicate, orally and in writing, within various sports settings and to different stakeholders in sport', '', 4, '2026-02-20 13:39:31', '2026-02-20 13:39:31'),
(182, 53, 'PLO5', 'Collect appropriate data and analyze situations related to sport management and industry issues', '', 5, '2026-02-20 13:39:31', '2026-02-20 13:39:31'),
(183, 6, 'PLO1', 'Define structure and function of organisms.', '', 1, '2026-02-20 14:33:13', '2026-02-21 14:33:43'),
(184, 6, 'PLO2', 'Describe the interactions between organisms and their environments.', '', 2, '2026-02-20 14:33:13', '2026-02-21 14:33:43'),
(185, 6, 'PLO3', 'Use instrumentation and proper techniques in biological sciences research correctly', '', 3, '2026-02-20 14:33:13', '2026-02-21 14:33:43'),
(186, 6, 'PLO4', 'Engage in critical thinking on problem solving activities on a biological topic.', '', 4, '2026-02-20 14:33:13', '2026-02-21 14:33:43'),
(187, 6, 'PLO5', 'Demonstrate proficiency in written by giving concise, clear and organized written communication about a biological concept.', '', 5, '2026-02-20 14:33:13', '2026-02-21 14:33:43'),
(188, 6, 'PLO6', 'Demonstrate proficiency in oral communication by giving concise, clear, and organized oral presentations on a biological topic.', '', 6, '2026-02-20 14:33:13', '2026-02-21 14:33:43'),
(193, 14, 'PLO1', 'Apply basic spatial analysis tools and other geographical methods to analyze the spatial structure and expansion of human settlements in urban and regional contexts.', '', 1, '2026-02-21 13:26:28', '2026-02-21 13:26:28'),
(194, 14, 'PLO2', 'Synthesize geospatial knowledge to solve a real-world problem (environment, economic, social, sustainable development, etc.) in Qatar and beyond.', '', 2, '2026-02-21 13:26:28', '2026-02-21 13:26:28'),
(195, 14, 'PLO3', 'Acquire, analyze, evaluate, interpret geographic data, and utilize the processes and techniques of geospatial data collection and analysis in conducting research.', '', 3, '2026-02-21 13:26:28', '2026-02-21 13:26:28'),
(196, 14, 'PLO4', 'Demonstrate understanding of basic spatial analysis, and evaluate the methodologies, processes, and findings of geospatial modeling techniques.', '', 4, '2026-02-21 13:26:28', '2026-02-21 13:26:28'),
(197, 7, 'PLO1', 'Apply critical thinking and demonstrate problem-solving skills in two or more of the major fields of chemistry.', '', 1, '2026-02-21 14:02:01', '2026-02-21 14:02:01'),
(198, 7, 'PLO2', 'Apply proper procedures and regulations for safe handling and use of chemicals and equipment in the laboratory.', '', 2, '2026-02-21 14:02:01', '2026-02-21 14:02:01'),
(199, 7, 'PLO3', 'Employ current analytical techniques and/or utilize instrumentation to conduct experiments, collect and analyze results, and work in teams.', '', 3, '2026-02-21 14:02:01', '2026-02-21 14:02:01'),
(200, 7, 'PLO4', 'Use modern literature search methods to obtain information about chemistry topics and write reports.', '', 4, '2026-02-21 14:02:01', '2026-02-21 14:02:01'),
(201, 7, 'PLO5', 'Conduct research (theoretical or practical) in the field of chemical sciences and document findings according to professional and ethical standards.', '', 5, '2026-02-21 14:02:01', '2026-02-21 14:02:01'),
(202, 7, 'PLO6', 'Communicate results to chemists and non-chemists.', '', 6, '2026-02-21 14:02:01', '2026-02-21 14:02:01'),
(203, 18, 'PLO1', 'Students will be able to explain the primary objectives of psychology and key characteristics of its major content domains.', '', 1, '2026-02-21 14:21:41', '2026-02-21 14:21:41'),
(204, 18, 'PLO2', 'Students will be able to apply psychological concepts to explain behavioural, emotional, cognitive, and social processes.', '', 2, '2026-02-21 14:21:41', '2026-02-21 14:21:41'),
(205, 18, 'PLO3', 'Student will be able to use effective research methodology to solve problems.', '', 3, '2026-02-21 14:21:41', '2026-02-21 14:21:41'),
(206, 18, 'PLO4', 'Students will develop basic working knowledge of psychological intervention methods.', '', 4, '2026-02-21 14:21:41', '2026-02-21 14:21:41'),
